import{_ as t,o as l,c as i,a3 as r}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"工具定义与宏注入","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/tool-calling/tool-definition.md","filePath":"user-guide/tools/llm-chat/tool-calling/tool-definition.md","lastUpdated":1780654734000}'),e={name:"user-guide/tools/llm-chat/tool-calling/tool-definition.md"};function n(s,o,a,g,d,c){return l(),i("div",null,[...o[0]||(o[0]=[r('<h1 id="工具定义与宏注入" tabindex="-1">工具定义与宏注入 <a class="header-anchor" href="#工具定义与宏注入" aria-label="Permalink to &quot;工具定义与宏注入&quot;">​</a></h1><p>智能体（Agent）感知工具能力的核心在于提示词（Prompt）中的工具定义。系统利用宏引擎实现了动态、按需的工具注入。</p><div><h2 id="关键宏定义" tabindex="-1">关键宏定义 <a class="header-anchor" href="#关键宏定义" aria-label="Permalink to &quot;关键宏定义&quot;">​</a></h2><p>在智能体的“角色设定”或“预设消息”中，可以使用以下宏：</p><ul><li><strong><code>{{tools}}</code></strong>： <ul><li><strong>功能</strong>：全量注入。根据当前智能体勾选启用的工具列表，生成完整的描述和参数 Schema。</li><li><strong>保底机制</strong>：如果配置中启用了工具调用但提示词中缺失此宏，系统可配置“保底注入”，自动将定义插入到对话历史之前。</li></ul></li><li><strong><code>{{tool_usage}}</code></strong>： <ul><li><strong>功能</strong>：注入协议说明。告诉模型如何构造调用指令（例如 VCP 协议的具体语法格式）。</li></ul></li><li><strong><code>{{tools::toolId}}</code></strong>： <ul><li><strong>功能</strong>：精确注入。仅注入指定 ID 的工具定义，适用于需要精简上下文的场景。</li></ul></li><li><strong><code>{{tool_context}}</code></strong>： <ul><li><strong>功能</strong>：上下文注入。根据当前智能体勾选启用的工具/插件，注入其实时运行时上下文。</li></ul></li><li><strong><code>{{tool_context::toolId}}</code></strong>： <ul><li><strong>功能</strong>：强制注入。无视开关状态，仅注入指定 ID 的工具/插件的运行时上下文。</li></ul></li></ul></div><h2 id="方法级深度配置" tabindex="-1">方法级深度配置 <a class="header-anchor" href="#方法级深度配置" aria-label="Permalink to &quot;方法级深度配置&quot;">​</a></h2><p>在“可用工具列表”中展开具体工具，可以进行微观控制：</p><ol><li><strong>方法开关</strong>：控制模型是否能看到并调用该工具下的特定子功能。</li><li><strong>描述覆盖 (Overrides)</strong>： <ul><li>你可以修改工具或方法的<strong>显示名称</strong>和<strong>描述</strong>。</li><li><strong>用途</strong>：如果默认的工具描述（通常由开发者编写）不够直观，或者你希望通过特定的引导词让模型更准确地理解何时使用该工具，可以通过覆盖功能进行调优。</li></ul></li><li><strong>示例注入</strong>：为方法提供具体的调用示例，通过 Few-shot 增强模型的遵循能力。</li></ol><h2 id="配置迁移" tabindex="-1">配置迁移 <a class="header-anchor" href="#配置迁移" aria-label="Permalink to &quot;配置迁移&quot;">​</a></h2><ul><li><strong>复制/粘贴 JSON</strong>：工具面板支持一键复制所有工具的启用状态和覆盖配置。</li><li><strong>用途</strong>：方便在不同的智能体之间快速同步复杂的工具调用策略，或备份调优后的描述。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">工具调用概览</a></li><li><a href="./execution-debug">执行监控与异步任务</a></li></ul>',11)])])}const _=t(e,[["render",n]]);export{h as __pageData,_ as default};
